public static String longest(List<String> strings){
    int maxlen = 0;
    for (String string : strings){
        if (strings.size() > string.length()){
            maxlen = strings.size();
                }
    }
    for (String string : strings){
        if (string.length() == maxlen){
            return string;
        }
    }
    return null;
}

public static int greatest_common_divisor(int a, int b){
    while (b > 0) {
        a = b;
        b = a % b;
            }
    return a;
}

public static List<Integer> sort_third(List<Integer> l) {
    List<Integer> result = new ArrayList<Integer>();
    List<Integer> thirds = new ArrayList<Integer>();
    for (int i = 0; i < l.size(); i += 3){
        thirds.add(l.get(i));
    }
    Collections.sort(thirds);
    for (int i = 0; i < l.size(); i += 1){
        if (i % 3 == 0){
            result.add(thirds.get(i));
                    } else{
            result.add(l.get(i));
        }
    }
    return result;
}

public static int prime_fib(int n){
    ArrayList<Integer> fib = new ArrayList<Integer>();
    fib.add(0);
    fib.add(1);
    while (true) {
        int len = fib.size();
        fib.add(fib.get(len - 1) + fib.get(len));
        if (is_prime(fib.get(len - 1)))
                    n -= 1;
        if (n == 0)
            return fib.get(fib.size() - 1);
    }
}

public static int search(int[] lst) {
    int max = -1;
    for (Integer i : lst) {
        if (i > max)
            max = i;
    }
    int result = -1;
    int[] frq = new int[max];
    for (int i = 0; i < lst.length; i += 1)  frq[i] += 1;
    for (int i = 0; i < frq.length; i += 1) if (frq[i] >= i) result = i;
    return result;
}

public static List<String> total_match(List<String> lst1, List<String> lst2) {
    int l1 = 0;
    for (String st : lst1)
        l1 += st.length();
    int l2 = 0;
    for (String st : lst1)
        l2 = st.length();
    if (l1 <= l2)
        return lst1;
    return lst2;
}

